VALUES
  ('pukao-7fec267e-moex-00112', 'pukao-7fec267e', 'pukao-7fec267e-moex-114-d1a761c9', 'sub-pukao-7fec267e-03', NULL, 'single_choice', '甲因未履行行政法上義務，遭主管機關課處怠金，並限期履行。甲對此處置不服，依法聲明異議後，經主 管機關之上級機關決定維持原處置，甲應如何救濟？', '["應依訴願法就上級機關之決定提起訴願", "應就其所承受之不利益請求國家賠償", "應提起行政訴訟請求撤銷該處置", "應就此決定提起憲法訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:13+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "401", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00113', 'pukao-7fec267e', 'pukao-7fec267e-moex-114-d1a761c9', 'sub-pukao-7fec267e-03', NULL, 'single_choice', '依政府資訊公開法規定，下列敘述何者錯誤？', '["有中華民國國籍而在國內無戶籍者，得申請提供政府資訊", "政府機關得主動公開，或依人民申請提供政府資訊", "應主動公開之政府資訊，政府機關未公開者，人民亦得申請提供", "申請提供之政府資訊，如已在網路公開者，得以告知申請人查詢方法以代提供"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:13+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "401", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00114', 'pukao-7fec267e', 'pukao-7fec267e-moex-114-d1a761c9', 'sub-pukao-7fec267e-03', NULL, 'single_choice', '甲於申請期間內在郵局以掛號郵寄方式向主管機關申請補助，因山區道路坍方，郵件無法送出，逾期10日 始到達機關。下列敘述何者正確？', '["以主管機關收受申請之日為準，故申請已逾期", "以甲交郵當日之郵戳為準，故申請未逾期", "因非可歸責於甲之事由，甲得於道路修復後20日內，申請回復原狀", "因非可歸責於甲之事由，申請期限得延後至郵件到達後10日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:13+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "401", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00115', 'pukao-7fec267e', 'pukao-7fec267e-moex-114-d1a761c9', 'sub-pukao-7fec267e-03', NULL, 'single_choice', '下列何者非屬正當行政程序之內涵？', '["公務員負有法定之迴避義務", "行政機關應依法提供相對人或利害關係人閱覽卷宗", "所有之行政決定均應讓相對人或利害關係人有陳述意見之機會", "行政處分之作成原則上應附具理由"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:13+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "401", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00116', 'pukao-7fec267e', 'pukao-7fec267e-moex-114-d1a761c9', 'sub-pukao-7fec267e-03', NULL, 'single_choice', '雲林縣口湖鄉公所否准低收入戶資格之行政處分，相對人如有不服，應以何者為訴願管轄機關？', '["雲林縣政府", "雲林縣口湖鄉公所", "內政部", "衛生福利部"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:13+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "401", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00117', 'pukao-7fec267e', 'pukao-7fec267e-moex-114-d1a761c9', 'sub-pukao-7fec267e-03', NULL, 'single_choice', '關於訴願之決定，下列敘述何者正確？', '["訴願不合法者，受理訴願機關應以無理由駁回之", "原行政處分所憑理由不當，但依其他理由認為正當者，應以訴願為有理由", "訴願事件涉及地方自治團體之地方自治事務者，其受理訴願之上級機關得就原行政處分之妥當性進行審查", "訴願之決定，自收受訴願書之次日起，原則上應於3個月內為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:13+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "401", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00118', 'pukao-7fec267e', 'pukao-7fec267e-moex-114-d1a761c9', 'sub-pukao-7fec267e-03', NULL, 'single_choice', '訴願審議委員會對於不合法之訴願提起者，得為訴願不受理之決定，下列情形何者不屬之？', '["對於事實行為提起訴願者", "對於已撤回之訴願重新提起者", "訴願書不合法定程式已於事後補正者", "行政處分經原處分機關依職權撤銷者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:13+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "401", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00119', 'pukao-7fec267e', 'pukao-7fec267e-moex-114-d1a761c9', 'sub-pukao-7fec267e-03', NULL, 'single_choice', '關於訴願再審之敘述，下列何者錯誤？', '["訴願人、參加人或利害關係人均得申請訴願再審", "再審申請人應向原處分機關提出再審申請", "再審事由必須是未於行政訴訟主張或非因故意而未主張", "如果申請人在訴願決定確定之後才知悉再審事由，必須在知悉時起30天內申請再審"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:13+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "401", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00120', 'pukao-7fec267e', 'pukao-7fec267e-moex-114-d1a761c9', 'sub-pukao-7fec267e-03', NULL, 'single_choice', '行政訴訟進行中當事人因故喪失訴訟能力，又無人為其聲請監護宣告，以致訴訟無法繼續進行時，依法應 選任特別代理人。相關處理方式，下列敘述何者錯誤？', '["當事人之親屬或利害關係人得向受訴法院之審判長聲請，選任特別代理人", "特別代理人可以代理為一切訴訟行為，但不包含捨棄、認諾、撤回或和解", "審判長為當事人選任律師為特別代理人，應同時酌定律師之酬金", "選任律師為特別代理人時，其酬金由行政法院先行負擔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:13+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "401", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00121', 'pukao-7fec267e', 'pukao-7fec267e-moex-114-d1a761c9', 'sub-pukao-7fec267e-03', NULL, 'single_choice', '主管機關查得甲未定期檢驗其所有之汽車，且超過應檢驗期限1個月以上，乃裁處罰鍰新臺幣1,800元並 吊扣其牌照。甲擬對罰鍰表示不服並請求主管機關返還牌照，其正確之救濟程序為何？', '["甲應依訴願法，向裁罰機關之上級機關提起訴願，並同時提起行政訴訟之給付訴訟", "甲應適用行政訴訟法簡易訴訟程序，逕向管轄行政法院起訴", "甲應適用行政訴訟法交通裁決事件訴訟程序，逕向管轄行政法院起訴", "甲得選擇依行政訴訟法簡易訴訟程序或交通裁決事件訴訟程序，逕向管轄行政法院起訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:13+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "401", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL)
